    const emails: string[] = council.emails?.length
      ? council.emails
      : parseEmailsFromSynthesis(council.synthesis || "");
    if (!emails[emailIndex]) return;

    const MAX_ROUNDS = 5;
    const dimKeys = ['opening','pain','tone','credibility','cta'] as const;
    setRefiningEmail(emailIndex);
