        const score = typeof g.total === "number" ? Math.min(10, Math.max(0, g.total)) : lastScore + 1;
        const dims = { opening:g.opening??0, pain:g.pain??0, tone:g.tone??0, credibility:g.credibility??0, cta:g.cta??0 };

